class Solution {
    public String minimizeStringValue(String s) {
        int[] count = new int[26];
        int total = 0;
        for (char c : s.toCharArray()) {
            if (c == '?') total++;
            else count[c - 'a']++;
        }
        StringBuilder sb = new StringBuilder();
        int idx = 0;
        for (char c : s.toCharArray()) {
            if (c != '?') {
                sb.append(c);
            } else {
                while (count[idx] != 0) idx++;
                sb.append((char) ('a' + idx));
                count[idx]++;
                total--;
                if (total == 0) idx = 26;
            }
        }
        return sb.toString();
    }
}
